def Assam():
    s=pyttsx3.init()
    s.say('Termed as the land of “Blue Hills and Red River” Assam is the gateway to the north eastern states and has been aptly described as the sentinel of Northeast India. Seven Indian States and two countries Bhutan and Bangladesh, surround Assam which is also close to India’s international borders with China and Myanmar.')
